var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"우리는 반드시 이 도시를 지켜야……","JPN":"私たちは必ずこの都市を守らねば……","ENG":"We must protect this city no matter what...","TWN":"我們一定要守住這座城市……"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hm?","TWN":"嗯？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"허신이 사라졌다고……?","JPN":"虚神が消えただと……？","ENG":"The Hollow God is gone...?","TWN":"虛神消失了……？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"제6종 침식체, 시그널 로스트……!","JPN":"第6種侵食体、シグナルロスト……！","ENG":"Category 6 C.O., signal lost...!","TWN":"第6類侵蝕體，喪失訊號……！"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"오지만디아스, 현장에서 무슨 일이 있었던 거야? 정말로 허신을 토벌했다고?","JPN":"オジマンディアス、現場で何があった？　本当に虚神を討伐したのか？","ENG":"Ozymandias, what happened on site? Did you really defeat the Hollow God?","TWN":"奧茲曼迪亞斯，現場究竟發生什麼事了？真的除掉虛神了嗎？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"내, 낸들 알아!? 갑자기 녀석이 증발해 버렸다고!","JPN":"し、知らないわよ！　いきなり目の前で消えちゃったし！","ENG":"How would I know?! It just evaporated out of nowhere!","TWN":"我、我怎麼會知道！？那傢伙突然就蒸發了啊！"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"설마, 다른 차원으로 도망간 건가? 하지만 어째서……?","JPN":"まさか、別の次元に逃げた？　でもどうして……？","ENG":"Did it escape to another dimension? But why...?","TWN":"難道是逃往其他次元了？但怎麼會……？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_QM","text":{"KOREA":"아니요, 허신은 소멸했습니다.","JPN":"いいえ、虚神は消滅しました。","ENG":"No. The Hollow God has been annihilated.","TWN":"不，已經消滅虛神了。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"다, 당신은……?","JPN":"あ、あなたは……？","ENG":"Y-you're...?","TWN":"你、你是……？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"제가 누구인지는 중요하지 않겠죠.","JPN":"私が誰か、それは今重要ではありませんわ。","ENG":"Who I am is not important.","TWN":"我是誰並不重要。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"저는 이것의 부름에 이끌려, 제 영지를 둘러보고 있었을 뿐이니까요.","JPN":"私はこれの呼びかけに導かれ、自分の領地を見回っていただけです。","ENG":"I was merely drawn here by its call and surveying my estate.","TWN":"我只是受到這個的呼喚，順道巡視了一下自己的領地而已。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭔데, 그 촌스러운 그 깡통 새는……?","JPN":"何なの、そのダサいボロ缶カラスは……？","ENG":"What's with that tacky tin can bird?","TWN":"那隻土土的罐裝鳥是什麼……？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"어라, 왠지 디자인이 낯이 익은데?","JPN":"あれ、なんか見覚えのあるデザインだな？","ENG":"Huh? The design feels strangely familiar.","TWN":"咦，我總覺得這設計有點眼熟？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"서, 설마? 코치……?","JPN":"えっ、待って……コーチ……？","ENG":"W-wait... Is that Coach...?","TWN":"難、難道說？是教練……？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그보다 대균열이 더 확장되기 전에, 서두르는 게 좋을 겁니다.","JPN":"それより、大亀裂がこれ以上拡張する前に急いだほうがいいですわ。","ENG":"We should hurry before the Grand Dimension Crevice expands any further.","TWN":"比起這個，在大峽谷進一步擴張前最好快點行動。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"허신이 쓰러진 지금이라면, 그 장치를 발동시킬 수 있을 테니까요.","JPN":"虚神が倒れた今なら、あの装置を稼働できるはずです。","ENG":"Now that the Hollow God has fallen, the device should be operable.","TWN":"現在虛神已被擊倒，應該能啟動那個裝置了。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"무언가 말 못할 사정이 있는 모양이지만…….","JPN":"何か口にできない事情があるようだが……","ENG":"It seems you have circumstances you cannot speak of...","TWN":"看來你似乎有什麼難言之隱……"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그대가 이곳에 있다는 것 또한 최고 관리자의 구상이겠지.","JPN":"君がここにいることもまた、最高管理者の策のうちなんだろうな。","ENG":"But your presence here must also be part of the Supreme Administrator's design.","TWN":"不過，你會出現在這裡，應該也是最高管理者的安排吧。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그렇다면, 이 전장을 이끄는 선봉장으로서 그대에게 감사를 표하지.","JPN":"ならば、この戦場を率いる先鋒隊長として君に礼を言わせてくれ。","ENG":"If so, as the vanguard leading this battlefield, I offer you my thanks.","TWN":"既然如此，作為引領這個戰場的先鋒指揮官，我向你致上謝意。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"흠, 뭔가 께름칙하지만…….","JPN":"ふむ、どうもすっきりしないところはあるが……","ENG":"It feels unsettling, but...","TWN":"嗯，雖然總覺得哪裡不太對勁……"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"이제 더는 망설일 시간이 없어.","JPN":"今は躊躇っている場合ではない。","ENG":"There's no time left to hesitate.","TWN":"但已經沒有時間猶豫了。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"좋아, 히페리온!","JPN":"よし、ハイペリオン！","ENG":"All right, Hyperion!","TWN":"好，海柏利昂！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"목표 지점에 선로전환기를 사출……!","JPN":"目標地点に線路転換器を射出……！","ENG":"Launch the Track Switcher at the target point...!","TWN":"向目標地點射出軌道轉換器……！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"얼마든지 맡겨주게! 시니어 르네!","JPN":"どんと任せてくれ！　シニア・ルネ！","ENG":"Leave it to me! Senior Renée!","TWN":"儘管交給我吧！Senior芮妮！"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"선로전환기 사출……!","JPN":"線路転換器、射出……！","ENG":"Launching the Track Switcher...!","TWN":"軌道轉換器射出……！"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"자, 모두들 서둘러……!","JPN":"皆、急いでくれ……！","ENG":"Everyone, move quickly...!","TWN":"好，大家動作快……！"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"전환기에 동력원을 연결하고, 공간이 융해되지 않도록 유산을 배치해……!","JPN":"転換器に動力源を繋いで、空間が融解しないよう遺産を配置するんだ……！","ENG":"Connect the power source to the Switcher and deploy the Legacy to prevent spatial fusion...!","TWN":"把動力源連接到轉換器，配置遺產避免空間熔解……！"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"어려운 발걸음을 하셨군요, 레지나 님.","JPN":"わざわざ足を運んでいただいたのですね、レジーナ様。","ENG":"You went through great trouble to come here, Miss Regina.","TWN":"您一路上辛苦了，蕾佳娜大人。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"부디, 저희의 불충을 용서하시길…….","JPN":"どうか私たちの不甲斐なさをお許しください……","ENG":"Please forgive our disloyalty.","TWN":"請您原諒我們的不忠……"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"고개를 드세요.","JPN":"顔を上げてください。","ENG":"Raise your head.","TWN":"抬起頭來吧。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};